/**
 * Type declaration for the auto-generated importMap.js that Payload writes.
 * Pure .js files aren't picked up by TypeScript when `allowJs` is false, so
 * Next.js's production build can't resolve the untyped import — this
 * declaration is enough to satisfy it without forcing the generated file
 * through the TS pipeline.
 */
import type { ImportMap } from 'payload';

export const importMap: ImportMap;
